/**
 * Usage log entry for observability.
 *
 * REDACTION: No API keys, tokens, or PII in logs.
 * All sensitive fields are hashed or omitted.
 *
 * STORAGE: Written to MongoDB (usage_logs collection) and/or
 * exported to external log aggregation.
 */
export type UsageLog = {
    /**
     * Log entry ID
     */
    id: string;
    timestamp?: string;
    correlation_id: string;
    workspace_id: string;
    /**
     * Reference only, not the key
     */
    api_key_id: string;
    method: string;
    path: string;
    /**
     * Normalized endpoint path
     */
    endpoint: string;
    status_code: number;
    duration_ms: number;
    prompt_tokens?: (number | null);
    completion_tokens?: (number | null);
    embedding_tokens?: (number | null);
    total_tokens?: (number | null);
    rag_trace?: (RAGTrace | null);
    error_code?: (string | null);
    error_message?: (string | null);
    /**
     * Hashed IP for privacy
     */
    client_ip_hash?: (string | null);
    /**
     * Hashed UA for privacy
     */
    user_agent_hash?: (string | null);
};

